mapper.select:
/* SQL ID : LessonCntsDAO.select 설 명 : 학습 콘텐츠 정보 */ SELECT A.SBJCT_LCTR_CONTS_ID , A.SBJCT_ID , A.SBJCT_LCTR_CLASTM_ID , (SELECT LCTR_CLASTM_SEQ FROM TB_LMS_SBJCT_LCTR_CLASTM WHERE SBJCT_LCTR_CLASTM_ID = A.SBJCT_LCTR_CLASTM_ID) AS LCTR_CLASTM_SEQ , A.LCTR_SCHDL_ID , (SELECT LCTR_SCHDL_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_SCHDL_ID = A.LCTR_SCHDL_ID) AS LCTR_SCHDL_SEQ , A.LESSON_TYPE_CD , A.LCTR_CONTSNM , A.LCTR_CONTS_SEQ , A.LCTR_CONTS_GBNCD , A.PRG_RFLTYN , A.LCTR_SDTTM , A.LCTR_EDTTM , A.LESSON_CNTS_FILE_LOC_CD , A.LESSON_CNTS_FILE_NM , A.LESSON_CNTS_FILE_PATH , A.LESSON_CNTS_URL , A.LESSON_CNTS_FILE_LOC_CD_M , A.LESSON_CNTS_FILE_NM_M , A.LESSON_CNTS_FILE_PATH_M , A.LESSON_CNTS_URL_M , A.RCMD_ATNDLC_MNTS , A.PRGRT_TYCD , A.INQYN , A.OTSDPRD_ATNDLCYN , A.OTSDPRD_ATNDLC_DAY_CNT , A.OTSDPRD_ATNDLC_RCG_STSCD , A.ATNDLC_STS_CHKYN , A.ATNDLC_NWIN_USEYN , A.LESSON_DATA_FILE_YN , A.LESSON_DATA_FILE_NM , A.LESSON_DATA_FILE_PATH , A.LESSON_DATA_FILE_URL , A.ATNDLC_MNTS , A.SKPLC_DIV_CD , A.VDO_CLAS_SDTTM , A.VDO_CLAS_EDTTM , A.VDO_CLAS_RM_PSWD , A.VDO_CLAS_EXPLN , A.VDO_CLAS_RM_CNTN_ID , A.CONTS_TXT , A.SUBTIT_KO , A.SUBTIT_EN , A.SCRIPT_KO , A.SCRIPT_EN , A.DELYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_SBJCT_LCTR_CONTS A WHERE A.SBJCT_LCTR_CONTS_ID = #{lessonCntsId}
AND A.SBJCT_ID = #{crsCreCd}
ORDER BY A.LCTR_CONTS_SEQ

/* SQL ID : LessonCntsDAO.list 설 명 : 학습 콘텐츠 목록 */ SELECT A.SBJCT_LCTR_CONTS_ID , A.SBJCT_ID , A.SBJCT_LCTR_CLASTM_ID , A.LCTR_SCHDL_ID , A.LESSON_TYPE_CD , A.LCTR_CONTSNM , A.LCTR_CONTS_SEQ , A.LCTR_CONTS_GBNCD , A.PRG_RFLTYN , A.LCTR_SDTTM , A.LCTR_EDTTM , A.LESSON_CNTS_FILE_LOC_CD , A.LESSON_CNTS_FILE_NM , A.LESSON_CNTS_FILE_PATH , A.LESSON_CNTS_URL , A.LESSON_CNTS_FILE_LOC_CD_M , A.LESSON_CNTS_FILE_NM_M , A.LESSON_CNTS_FILE_PATH_M , A.LESSON_CNTS_URL_M , A.RCMD_ATNDLC_MNTS , A.PRGRT_TYCD , A.INQYN , A.OTSDPRD_ATNDLCYN , A.OTSDPRD_ATNDLC_DAY_CNT , A.OTSDPRD_ATNDLC_RCG_STSCD , A.ATNDLC_STS_CHKYN , A.ATNDLC_NWIN_USEYN , A.LESSON_DATA_FILE_YN , A.LESSON_DATA_FILE_NM , A.LESSON_DATA_FILE_PATH , A.LESSON_DATA_FILE_URL , A.ATNDLC_MNTS , A.SKPLC_DIV_CD , A.VDO_CLAS_SDTTM , A.VDO_CLAS_EDTTM , A.VDO_CLAS_RM_PSWD , A.VDO_CLAS_EXPLN , A.VDO_CLAS_RM_CNTN_ID , A.DELYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_SBJCT_LCTR_CONTS A
AND A.SBJCT_LCTR_CONTS_ID = #{lessonCntsId}
AND A.SBJCT_ID = #{crsCreCd}
AND A.LCTR_SCHDL_ID = #{lessonScheduleId}
AND A.SBJCT_LCTR_CLASTM_ID = #{lessonTimeId}
AND A.DELYN = #{delYn}
AND A.PRG_RFLTYN = #{prgrYn}
ORDER BY A.LCTR_CONTS_SEQ

mapper.insert:
/*
   SQL ID : LessonCntsDAO.insert
	설  명 : 학습 콘텐츠 등록
*/
INSERT INTO TB_LMS_SBJCT_LCTR_CONTS (
	  SBJCT_LCTR_CONTS_ID
	, SBJCT_ID
	, SBJCT_LCTR_CLASTM_ID
	, LCTR_SCHDL_ID
	, LESSON_TYPE_CD
	, LCTR_CONTSNM
	, LCTR_CONTS_SEQ
	, LCTR_CONTS_GBNCD
	, PRG_RFLTYN
