	, LESSON_CNTS_FILE_LOC_CD
	, LESSON_CNTS_FILE_NM
	, LESSON_CNTS_FILE_PATH
	, LESSON_CNTS_URL
	, LESSON_CNTS_FILE_LOC_CD_M
	, LESSON_CNTS_FILE_NM_M
	, LESSON_CNTS_FILE_PATH_M
	, LESSON_CNTS_URL_M
	, RCMD_ATNDLC_MNTS
