	, ATNDLC_NWIN_USEYN
	, LESSON_DATA_FILE_YN
	, LESSON_DATA_FILE_NM
	, LESSON_DATA_FILE_PATH
	, LESSON_DATA_FILE_URL
	, ATNDLC_MNTS
	, SKPLC_DIV_CD
	, VDO_CLAS_SDTTM
	, VDO_CLAS_EDTTM
	, VDO_CLAS_RM_PSWD
	, VDO_CLAS_EXPLN
	, VDO_CLAS_RM_CNTN_ID
	, CONTS_TXT
	, SUBTIT_KO
	, SUBTIT_EN
	, SCRIPT_KO
	, SCRIPT_EN
	, DELYN
	, RGTR_ID
	, FRST_INQ_DTTM
) VALUES (
	  #{lessonCntsId}
	, #{crsCreCd}
	, #{lessonTimeId}
	, #{lessonScheduleId}
	, #{lessonTypeCd}
	, #{lessonCntsNm}
	, #{lessonCntsOrder}
	, #{cntsGbn}
	, #{prgrYn}
	, #{lessonStartDttm}
	, #{lessonEndDttm}
	, #{lessonCntsFileLocCd}
	, #{lessonCntsFileNm}
	, #{lessonCntsFilePath}
	, #{lessonCntsUrl}
	, #{lessonCntsFileLocCdM}
	, #{lessonCntsFileNmM}
	, #{lessonCntsFilePathM}
	, #{lessonCntsUrlM}
	, #{recmmdStudyTime}
	, #{prgrRatioTypeCd}
	, #{viewYn}
	, #{periodOutLearnYn}
	, #{periodOutLearnDayCnt}
	, #{periodOutLearnStatusCd}
	, #{learnStatusCheckYn}
	, #{newWindowLearnYn}
	, #{lessonDataFileYn}
	, #{lessonDataFileNm}
	, #{lessonDataFilePath}
	, #{lessonDataFileUrl}
	, #{attplanTime}
	, #{skplcDivCd}
	, #{vcLearnStartDttm}
	, #{vcLearnEndDttm}
	, #{vcLearnRoomPwd}
	, #{vcLearnDesc}
	, #{vcRoomRelId}
	, #{cntsText}
	, #{subtitKo}
	, #{subtitEn}
	, #{scriptKo}
	, #{scriptEn}
	, 'N'
	, #{rgtrId}
	, FN_DTTM()
)

mapper.update:
/*
   SQL ID : LessonCntsDAO.update
	설  명 : 학습 콘텐츠 수정
*/
UPDATE TB_LMS_SBJCT_LCTR_CONTS
SET
	  LCTR_CONTSNM		= #{lessonCntsNm}
	, LCTR_CONTS_SEQ		= #{lessonCntsOrder}
	, LCTR_CONTS_GBNCD				= #{cntsGbn}
	, PRG_RFLTYN				= #{prgrYn}

	, RCMD_ATNDLC_MNTS 	= #{recmmdStudyTime}

	, LESSON_CNTS_FILE_NM	= #{lessonCntsFileNm}
	, LESSON_CNTS_FILE_PATH = #{lessonCntsFilePath}
	, LESSON_CNTS_URL		= #{lessonCntsUrl}
	, CONTS_TXT				= #{cntsText}
	, SUBTIT_KO				= #{subtitKo}
	, SUBTIT_EN				= #{subtitEn}
	, SCRIPT_KO				= #{scriptKo}
	, SCRIPT_EN				= #{scriptEn}
	, MDFR_ID				= #{mdfrId}
	, MOD_DTTM				= FN_DTTM()
WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

mapper.delete:
/*
   SQL ID : LessonCntsDAO.list
	설  명 : 학습 콘텐츠 삭제
*/
DELETE FROM TB_LMS_SBJCT_LCTR_CONTS
WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

mapper.select:
		/*
             SQL ID : LessonCntsDAO.selectLessonCntsOrderMax
             설  명 : 학습 콘텐츠 순서 최대값
         */
		SELECT 
			NVL(MAX(LCTR_CONTS_SEQ), 0) + 1 
		  FROM TB_LMS_SBJCT_LCTR_CONTS 
		 WHERE SBJCT_ID = #{crsCreCd} 
		   AND SBJCT_LCTR_CLASTM_ID = #{lessonTimeId}

mapper.update:
/*
   SQL ID : LessonCntsDAO.updateCntsNm
	설  명 : 학습 콘텐츠 수정
*/
UPDATE TB_LMS_SBJCT_LCTR_CONTS
SET
	  LCTR_CONTSNM		= #{lessonCntsNm}
	, MDFR_ID				= #{mdfrId}
	, MOD_DTTM				= FN_DTTM()
WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

mapper.insert:
        /*
             SQL ID : insertLessonCntsListForTrans
             설  명 : 콘텐츠정보 목록 저장(선수강과목 이관용)
        */
        INSERT IGNORE INTO TB_LMS_SBJCT_LCTR_CONTS (
			  SBJCT_LCTR_CONTS_ID
			, SBJCT_ID
			, SBJCT_LCTR_CLASTM_ID
			, LCTR_SCHDL_ID
			, LESSON_TYPE_CD
			, LCTR_CONTSNM
			, LCTR_CONTS_SEQ
			, LCTR_CONTS_GBNCD
			, PRG_RFLTYN
			, LESSON_CNTS_URL
			, RCMD_ATNDLC_MNTS
			, INQYN
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
        ) VALUES

		(
			  #{item.lessonCntsId}
			, #{item.crsCreCd}
			, #{item.lessonTimeId}
			, #{item.lessonScheduleId}
			, #{item.lessonTypeCd}
			, #{item.lessonCntsNm}
			, #{item.lessonCntsOrder}
			, #{item.cntsGbn}
			, #{item.prgrYn}
			, #{item.lessonCntsUrl}
			, #{item.recmmdStudyTime}
